*����������������� const uint cTDTrianglesType = 0;
const uint cTDQuadsType = 1;
const uint cTDLineStripsType = 2;
const uint cTDLinesType = 3;
const uint cTDPointPrimsType = 4;

uint TDInputPrimType(uint inputIndex, uint primIndex)
{

	uint primType = 0;

	if(primIndex < TDInputPrimsStartIndex(inputIndex, cTDQuadsType))
	{
		primType = cTDTrianglesType;
	}
	else if(primIndex < TDInputPrimsStartIndex(inputIndex, cTDLineStripsType))
	{
		primType = cTDQuadsType;
	}
	else if(primIndex < TDInputPrimsStartIndex(inputIndex, cTDLinesType))
	{
		primType = cTDLineStripsType;
	}
	else if(primIndex < TDInputPrimsStartIndex(inputIndex, cTDPointPrimsType))
	{
		primType = cTDLinesType;
	}
	else if(primIndex < TDInputNumPrims(inputIndex))
	{
		primType = cTDPointPrimsType;
	}
	return primType;
}

