void main() 			
{			
	const uint id = TDIndex();		
	if(id >= TDNumElements())		
		return;	

	if (TDPassIndex() == 0)		
	{		
		// inclusive scan	
		HashIdCountSum[id] = TDIn_HashIdCount();	

		/*
		// exclusive scan	
		if (id == 0)	
			HashIdCountSum[0] = 0;
		else	
			HashIdCountSum[id] = iHashIdCount[id - 1]; 
		*/

	}		
	else		
	{		
		uint offset = uint(pow(2, (TDPassIndex() - 1)));	
		if (id >= offset)	
		{	
			HashIdCountSum[id] = TDIn_HashIdCountSum(0, id - offset) + TDIn_HashIdCountSum(0, id);
		}	
	}		
}

