*�����������������&void main() {
    const uint id = TDIndex();
    if(id >= TDNumElements())
        return;

    vec3 originalPos = TDIn_P();

    // Make it pulse in and out
    float pulse = 1.0 + 0.3 * sin(uTime);
    vec3 pos = originalPos * pulse;

    // Add wave deformation
    float wave = 0.2 * sin(uTime * 2.0 + originalPos.x);
    pos.y += wave;
    P[id] = pos;

    // Calculate ripple intensity (0-1 value based on deformation)
    float rippleIntensity = abs(wave) * 5.0;  // Multiply by 5 to make it more visible
    rippleIntensity = clamp(rippleIntensity, 0.0, 1.0);  // Clamp to 0-1 range
    Ripple[id] = rippleIntensity;

    // Use original position for stable color pattern that scales with pulse
    float colorFreq = 5.0 / pulse;  // Color pattern scales with sphere size

    vec4 color = vec4(
        0.5 + 0.5 * sin(originalPos.x * colorFreq + uTime),
        rippleIntensity,  // Green channel shows ripple intensity
        0.5 + 0.5 * sin(originalPos.z * colorFreq + uTime),
        1.0
    );
    Color[id] = color;
}

