*�����������������Yvoid main() {
    const uint id = TDIndex();
    if(id >= TDNumElements())
        return;

    vec3 originalPos = TDIn_P();

    // Make it pulse in and out
    float pulse = 1.0 + 0.3 * sin(uTime);
    vec3 pos = originalPos * pulse;

    // Add wave deformation
    pos.y += 0.2 * sin(uTime * 2.0 + pos.x);
    P[id] = pos;

    // Calculate colors based on original position so pattern scales with the sphere
    // Scale the color frequency by the pulse to make colors stretch/compress with size
    float colorFreq = 5.0 / pulse;  // Inverse relationship keeps pattern consistent

    vec4 color = vec4(
        0.5 + 0.5 * sin(originalPos.x * colorFreq + uTime),
        0.5 + 0.5 * sin(originalPos.y * colorFreq + uTime),
        0.5 + 0.5 * sin(originalPos.z * colorFreq + uTime),
        1.0
    );
    Color[id] = color;
}
